// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('Click button search', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('Click button search', async function() {
    await driver.get("http://localhost:4200/home");
    await driver.manage().window().setRect({ width: 1900, height: 1020 });
    await driver.findElement(By.css(".ant-row:nth-child(3) .ant-typography")).click();
    await driver.findElement(By.xpath("//span[contains(.,\'公開専門スキル一覧\')]")).click();
    await driver.findElement(By.css(".main_button > span")).click();
    {
      const element = await driver.findElement(By.css(".main_button > span"));
      await driver.actions({ bridge: true }).moveToElement(element).perform();
    }
    {
      const element = await driver.findElement(By.CSS_SELECTOR, "body");
      await driver.actions({ bridge: true }).moveToElement(element, 0, 0).perform();
    }
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(1)")).click();
    assert(await driver.findElement(By.xpath("//th[contains(.,\'部署\')]")).getText() == "部署");
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(2)")).click();
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(2)")).click();
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(2)")).click();
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(2)")).click();
    {
      const element = await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(2)"));
      await driver.actions({ bridge: true}).doubleClick(element).perform();
    }
    await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(2)")).click();
    assert(await driver.findElement(By.xpath("//th[contains(.,\'バージョン\')]")).getText() == "バージョン");
    assert(await driver.findElement(By.xpath("//th[contains(.,\'最終更新者\')]")).getText() == "最終更新者");
    assert(await driver.findElement(By.xpath("//th[contains(.,\'最終更新日\')]")).getText() == "最終更新日");
    assert(await driver.findElement(By.xpath("//th[contains(.,\'公開日\')]")).getText() == "公開日");
  });
});
